\section{Explicação Didática}
\textbf{Explicação resumida:} O problema exige ajustar o preço por porção para que o custo total de 5 porções mais a taxa de entrega permaneça constante após o aumento da taxa. \\
\textbf{Passo a passo:}
\begin{enumerate}
    \item Calcular o custo total atual:
    \begin{equation*}
    5 \times 25 + 10 = 135.
    \end{equation*}
    \item Montar a equação para o novo custo total com o novo preço:
    \begin{equation*}
    5x + 15 = 135.
    \end{equation*}
    \item Isolar o termo com $x$:
    \begin{equation*}
    5x = 135 - 15 = 120.
    \end{equation*}
    \item Calcular o valor de $x$:
    \begin{equation*}
    x = \frac{120}{5} = 24.
    \end{equation*}
    \item Concluir que o novo preço por porção é R$24,00.
\end{enumerate}

\textbf{Erros comuns:}
\begin{itemize}
    \item Ignorar o aumento da taxa de entrega ao calcular.
    \item Diminuir o preço por porção de forma incorreta.
    \item Somar a nova taxa sem ajustar o preço.
    \item Confundir a taxa fixa com o preço por porção.
\end{itemize}

\textbf{Dicas para ensino:}
\begin{itemize}
    \item Utilizar exemplos palpáveis para ilustrar o custo total.
    \item Incentivar a formulação da equação antes de resolver.
    \item Destacar o conceito de balancear o custo antes e depois da mudança.
    \item Diferenciar claramente taxa fixa e preço variável.
\end{itemize}

